// src/schemas/time-tracking.schemas.ts
import { z as z4 } from "zod";
var timesheetStatusSchema = z4.nativeEnum(TimesheetStatus);
var createTimeEntrySchema = z4.object({
  taskId: z4.string().uuid().optional(),
  projectId: z4.string().uuid(),
  description: z4.string().min(1).max(500).optional(),
  startTime: z4.string().datetime(),
  endTime: z4.string().datetime().optional(),
  duration: z4.number().min(0).optional(),
  // In seconds
  isBillable: z4.boolean().default(true),
  billableRate: z4.number().min(0).optional(),
  tags: z4.array(z4.string()).max(10).optional()
}).refine(
  (data) => {
    if (data.endTime) {
      return new Date(data.endTime) > new Date(data.startTime);
    }
    return true;
  },
  { message: "End time must be after start time", path: ["endTime"] }
).refine(
  (data) => {
    if (data.endTime && data.duration) {
      const calculatedDuration = (new Date(data.endTime).getTime() - new Date(data.startTime).getTime()) / 1e3;
      return Math.abs(calculatedDuration - data.duration) < 1;
    }
    return true;
  },
  { message: "Duration must match the time difference", path: ["duration"] }
).refine(
  (data) => {
    if (data.endTime) {
      const durationHours = (new Date(data.endTime).getTime() - new Date(data.startTime).getTime()) / (1e3 * 60 * 60);
      return durationHours <= 24;
    }
    if (data.duration) {
      return data.duration <= 24 * 60 * 60;
    }
    return true;
  },
  { message: "Time entry cannot exceed 24 hours", path: ["endTime"] }
);
